import pytest
import requests
from datetime import datetime, timezone

def <post_obs_upper>(base_url, token, value):
    headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/fhir+json"}
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "category": [{"coding": [{"system": "http://terminology.hl7.org/CodeSystem/observation-category", "code": "vital-signs"}]}],
        "code": {"coding": [{"system": "http://loinc.org", "code": "8867-4"}]},
        "effectiveDateTime": datetime.now(timezone.utc).isoformat(),
        "valueQuantity": {"value": value, "unit": "beats/min", "system": "http://unitsofmeasure.org", "code": "/min"}
    }
    return requests.post(f"{base_url}/Observation", json=payload, headers=headers)

def test_vital_signs_boundary_heart_rate_upper_limit_flagged(<auth_fixture>, base_url):
    token = <auth_fixture>.clinician_token()
    resp_at = <post_obs_upper>(base_url, token, 250)
    assert resp_at.status_code == 201
    assert resp_at.json().get("status") == "final"
    resp_above = <post_obs_upper>(base_url, token, 251)
    assert resp_above.status_code == 201
    body_above = resp_above.json()
    flag = ("reviewTask" in body_above) or any(
        e.get("url", "").endswith("out-of-range") for e in body_above.get("extension", [])
    )
    assert flag, "Value above upper boundary must be flagged"
